import{_ as e,o as t,c as r,a0 as n}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"🛡️ 網頁端領地權限管理","description":"","frontmatter":{},"headers":[],"relativePath":"Web-Claims-Management.md","filePath":"Web-Claims-Management.md"}'),o={name:"Web-Claims-Management.md"};function l(i,a,s,d,c,m){return t(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="🛡️-網頁端領地權限管理" tabindex="-1">🛡️ 網頁端領地權限管理 <a class="header-anchor" href="#🛡️-網頁端領地權限管理" aria-label="Permalink to &quot;🛡️ 網頁端領地權限管理&quot;">​</a></h1><p>玩家可在網頁端直觀管理個人名下的保護領地，並為好友設定精細的共建權限。</p><hr><h2 id="🗺️-1-領地列表與資訊" tabindex="-1">🗺️ 1. 領地列表與資訊 <a class="header-anchor" href="#🗺️-1-領地列表與資訊" aria-label="Permalink to &quot;🗺️ 1. 領地列表與資訊&quot;">​</a></h2><p>在 <strong>「領地管理」</strong> 面板中，會列出您目前擁有的所有領地卡片，包含：</p><ul><li>領地流水號 ID</li><li>領地對角座標範圍</li><li>所屬世界維度 (如 <code>minecraft:overworld</code>)</li></ul><hr><h2 id="⚙️-2-四大核心權限配置" tabindex="-1">⚙️ 2. 四大核心權限配置 <a class="header-anchor" href="#⚙️-2-四大核心權限配置" aria-label="Permalink to &quot;⚙️ 2. 四大核心權限配置&quot;">​</a></h2><p>您可以針對指定領地，為其他玩家（輸入玩家名稱）設定以下四種權限：</p><ol><li><strong>Build (建造)</strong>：是否允許放置方塊。</li><li><strong>Break (破壞)</strong>：是否允許破壞方塊.</li><li><strong>Containers (容器)</strong>：是否允許開啟箱子、熔爐、木桶等儲存容器。</li><li><strong>Interact (互動)</strong>：是否允許使用按鈕、拉桿、門、壓力板等紅石互動機關。</li></ol><p>您可以隨時在網頁上勾選/取消勾選對應權限，或是一鍵撤銷（移除）該玩家在該領地的所有存取授權。</p>',11)])])}const p=e(o,[["render",l]]);export{h as __pageData,p as default};
